async function processPayment(cardNumber, amount, timeoutMs = 10000) {
  // Input validation
  if (!isValidCardNumber(cardNumber)) {
    throw new Error('Invalid card number');
  }

  if (!isValidAmount(amount)) {
    throw new Error('Invalid amount');
  }

  // Tokenize card number (never send raw PAN to backend)
  const paymentToken = await tokenizeCardNumber(cardNumber);

  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

    const response = await fetch('https://payment-api.internal/charge', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${await getAuthToken()}`,
      },
      body: JSON.stringify({ 
        token: paymentToken, 
        amount: parseFloat(amount).toFixed(2) 
      }),
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(`Payment failed: ${errorData.message || response.statusText}`);
    }

    const result = await response.json();
    return result.success === true;

  } catch (error) {
    if (error.name === 'AbortError') {
      throw new Error('Payment request timeout');
    }
    // Log error without sensitive data
    console.error('Payment processing failed:', error.message);
    throw error;
  }
}

